Here are pytest‑style unit tests covering happy paths, edge cases, and error cases. No special formatting is used.

```
import pytest
from your_module import snake_to_camel

def test_happy_path_simple():
    assert snake_to_camel("hello_world") == "helloWorld"

def test_happy_path_multiple_parts():
    assert snake_to_camel("this_is_a_test") == "thisIsATest"

def test_single_word():
    assert snake_to_camel("hello") == "hello"

def test_empty_string():
    # split on empty string -> [''], so result should be empty string
    assert snake_to_camel("") == ""

def test_leading_underscore():
    # split -> ['', 'hello'] so first element is '' and second gets capitalized
    assert snake_to_camel("_hello") == "Hello"

def test_trailing_underscore():
    # split -> ['hello', ''], capitalizing '' gives ''
    assert snake_to_camel("hello_") == "hello"

def test_multiple_consecutive_underscores():
    # '' parts become '' and capitalize('') is ''
    # example: parts = ['hello', '', 'world']
    assert snake_to_camel("hello__world") == "helloWorld"

def test_only_underscores():
    # e.g. '__' -> ['', '', ''] -> result is ''
    assert snake_to_camel("__") == ""

def test_non_string_input_raises():
    with pytest.raises(AttributeError):
        snake_to_camel(None)

def test_numeric_string():
    assert snake_to_camel("value_1") == "value1"
